//#region src/composables/useFeatures/adapters/launchdarkly/index.ts
var LaunchDarklyFeatureAdapter = class {
	constructor(client) {
		this.client = client;
	}
	setup(onUpdate) {
		const collect = () => {
			const allFlags = this.client.allFlags();
			const flags = {};
			for (const [key, value] of Object.entries(allFlags)) flags[key] = typeof value === "boolean" ? value : {
				$value: true,
				$variation: value
			};
			return flags;
		};
		function onChange() {
			onUpdate(collect());
		}
		this.client.on("change", onChange);
		this.disposeFn = () => this.client.off("change", onChange);
		return collect();
	}
	dispose() {
		this.disposeFn();
	}
	disposeFn = () => {};
};
//#endregion
export { LaunchDarklyFeatureAdapter as t };
